export const APP_ROUTES = {
  AUTH: {
    REGISTER: "/register",
    SIGN_IN: "/sign-in",
    REQUEST_FORGOT_PASSWORD: "/request-forgot-password",
    FORGOT_PASSWORD: (params?: {
      email?: string;
      phone?: string;
      mediaType?: string;
    }) => {
      const baseUrl = "/forgot-password";

      if (!params) return baseUrl;

      const searchParams = new URLSearchParams();
      if (params.email) searchParams.append("email", params.email);
      if (params.phone) searchParams.append("phone", params.phone);
      if (params.mediaType) searchParams.append("mediaType", params.mediaType);

      const query = searchParams.toString();
      return query ? `${baseUrl}?${query}` : baseUrl;
    },
    RESET_PASSWORD: "/reset-password",
    VERIFY_OTP: "/verify-otp",
    CREATE_PASSWORD: "/create-password",
    CHANGE_TEMP_PASSWORD: "/change-temp-password",
  },

  APP: {
    ROOT: "/",
    MY_DEALS: "/my-offers",
    // AUCTION: "/auction", // Not in MVP
    TICKETS: "/tickets",
    // AUTHENTICATION: "/authentications", // Not in MVP
    PRICING: "/pricing",
    ABOUT: "/about",
    CONTACT: "/contact",
    // SUBSCRIOTION: "/subscription", // Not in MVP
    FAQ: "/faq",
    POLICY: "/privacy-policy",
    TERMS: "/terms",
  },

  WALLET: {
    ROOT: "/wallet",
    PAYMENT_HISTORY: "/wallet/payment-history",
    WITHDRAW: "/wallet/withdraw",
    WITHDRAWAL_REQUESTS: "/wallet/withdrawal-requests",
    WITHDRAWAL_REQUEST_NEW: "/wallet/withdrawal-requests/new",
    PAYPAL_METHODS: {
      CONNECT: "/wallet/payment-methods/paypal/connect",
      SUCCESS: "/paypal-methods/success",
      CANCEL: "/paypal-methods/cancel",
    },
  },

  PROFILE: "/profile",

  WELCOME: "/welcome",

  KYC: {
    RETURN: "/kyc/return",
  },

  SERVICES: {
    BUYBACK: "/services/buyback",
    DIRECT_SALE: "/services/permanent-sale",
    OUR_METHOD: "/services/our-method",
  },
  BUYBACK_REQUESTS: {
    CREATE: "/quote-request/create",
    LIST: "/quote-request",
    DETAIL: (id: string) => `/quote-request/${id}`,
  },

  BUYBACKS: {
    LIST: "/buybacks",
    DETAIL: (id: string) => `/buybacks/${id}`,
    PAY: (id: string) => `/buybacks/${id}/pay`,
  },

  ADMIN: {
    ROOT: "/admin",
    USERS: "/admin/users",
    CUSTODY: "/admin/custody-management",
    USER_MANAGEMENT: {
      ROOT: "/admin/users",
      ADMINS: "/admin/users/admins",
      SELLERS: "/admin/users/sellers",
      AUTHENTICATORS: "/admin/users/authenticators",
      ROLES: "/admin/users/roles-permissions",
    },
    SETTINGS: "/admin/settings",
    BUYBACK_REQUESTS: "/admin/finance/quotes",
    BUYBACK_REQUEST_DETAIL: (id: string) => `/admin/finance/quotes/${id}`,
    BUYBACK_REQUEST_CREATE: "/admin/finance/quotes/create",
    BUYBACKS: {
      LIST: "/admin/finance/active-buybacks",
      DETAIL: (id: string) => `/admin/finance/active-buybacks/${id}`,
    },
    FINANCE: {
      QUOTES: "/admin/finance/quotes",
      ACTIVE_BUYBACKS: "/admin/finance/active-buybacks",
      ACTIVE_BUYBACK_DETAIL: (id: string) =>
        `/admin/finance/active-buybacks/${id}`,
      UNSETTLED_BUYBACKS: "/admin/finance/unsettled-buybacks",
      CLOSED_BUYBACKS: "/admin/finance/closed-buybacks",
    },
    CATEGORIES: {
      ROOT: "/admin/categories",
      BRANDS: "/admin/categories/brands",
      MODELS: "/admin/categories/models",
      DETAIL: (categoryId: string, categorySlug: string) =>
        `/admin/categories/${categoryId}/${categorySlug}`,
      CATEGORY_MODELS: (categoryId: string, categorySlug: string) =>
        `/admin/categories/${categoryId}/${categorySlug}/models`,
      BRAND_DETAIL: (
        categoryId: string,
        categorySlug: string,
        brandId: string,
        brandSlug: string,
      ) =>
        `/admin/categories/${categoryId}/${categorySlug}/${brandId}/${brandSlug}`,
    },
    PAYMENTSMANAGEMENTS: {
      PAYMENTS: "/admin/payment-management/payments",
      // SUBSCRIPTIONS: "/admin/payment-management/subscriptions", // Not in MVP
    },
    TICKETS: {
      ROOT: "/admin/tickets",
      ACTIVE: "/admin/tickets",
      ARCHIVE: "/admin/tickets?tab=archive",
      DETAIL: (id: string) => `/admin/tickets/${id}`,
    },
    USERPERMISSIONS: {
      ROLESPERMISSIONS: "/admin/users/roles-permissions",
    },
    ASSETS: {
      IN_CUSTODY: "/admin/assets/in-custody",
      RELEASED: "/admin/assets/released",
      DETAIL: (id: string) => `/admin/assets/${id}`,
    },
    WITHDRAWAL_REQUESTS: "/admin/payment-management/withdrawal-requests",
  },

  AUTHENTICATOR: {
    PROFILE: "/authenticator/profile",
    NEW_REQUESTS: "/authenticator/authentication/new-requests",
    HISTORY: "/authenticator/authentication/history",
    VALUATION_DETAIL: (id: string) => `/authenticator/authentication/${id}`,
    CATEGORIES: "/authenticator/categories",
  },

  LEGAL: {
    TERMS: "/terms",
  },

  SETTINGS: "/settings",

  TICKETS: {
    ROOT: "/tickets",
    ACTIVE: "/tickets",
    ARCHIVE: "/tickets?tab=archive",
    CREATE: "/tickets/create",
    DETAIL: (id: string) => `/tickets/${id}`,
  },

  CONTACTS: "/contacts",

  SUPPORT: "/support",
} as const;

"use client";

import {
  CircleUserRound,
  LogOutIcon,
  ScrollTextIcon,
  WalletCards,
} from "lucide-react";
import { signOut, useSession } from "next-auth/react";
import Image from "next/image";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { type FC, useEffect, useState } from "react";

import { useProfile } from "@/entities/profile";
import { useSignedFileUrl } from "@/shared/api/query-hooks/use-file-upload";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { UserAvatar } from "@/shared/ui/user-avatar/user-avatar";
import { cn } from "@/shared/lib/ui/cn";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/shared/ui/dropdown-menu";
import { HeaderNotificationsDropdown } from "./notifications-dropdown";
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuTrigger,
} from "@/shared/ui/shadcn/navigation-menu";
import { MobileMenu } from "./mobile-menu";

const ABOUT_LINKS = [
  { title: "About LuxFlow", href: APP_ROUTES.APP.ABOUT },
  { title: "Our Method", href: APP_ROUTES.SERVICES.OUR_METHOD },
  { title: "Contact Us", href: APP_ROUTES.APP.CONTACT },
  { title: "Support", href: APP_ROUTES.SUPPORT },
  { title: "FAQs", href: APP_ROUTES.APP.FAQ },
];

const NAV_LINKS = [
  { title: "Home", href: "/" },
  { title: "Buyback", href: "/services/buyback" },
  { title: "Permanent Sale", href: "/services/permanent-sale" },
];

interface HeaderProps {
  className?: string;
}

export const Header: FC<HeaderProps> = ({ className }) => {
  const { status } = useSession();
  const isAuthenticated = status === "authenticated";
  const router = useRouter();
  const pathname = usePathname();

  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const isLanding = pathname === "/";
  const isTransparent = isLanding && !scrolled;

  const { data: profile } = useProfile();
  const photoFileId = profile?.photoFileId ?? null;
  const { data: photoData } = useSignedFileUrl(
    photoFileId ?? "",
    !!photoFileId,
  );
  const avatarSrc = photoData?.url ?? null;

  const handleLogout = async () => {
    await signOut({ redirect: false });
    router.push(APP_ROUTES.AUTH.SIGN_IN);
    router.refresh();
  };

  const whatsappUrl = "https://wa.me/971542739213";

  return (
    <header
      className={cn(
        "new-design fixed top-0 right-0 left-0 z-50 w-full font-[500] font-new-sans text-sm transition-colors duration-300",
        isTransparent
          ? "border-background border-b-[0.5px] bg-transparent text-background"
          : "border-border border-b bg-background",
        className,
      )}
    >
      <div className="mx-auto max-w-[1720px] px-4 py-3 min-[1172px]:px-10">
        <div className="hidden grid-cols-3 items-center lg:grid">
          <nav className="flex items-center gap-4 xl:gap-6">
            {NAV_LINKS.map((link) => (
              <Link
                className="whitespace-nowrap transition-opacity hover:opacity-60"
                href={link.href}
                key={link.href}
              >
                {link.title}
              </Link>
            ))}

            {isAuthenticated && (
              <Link
                className="whitespace-nowrap transition-opacity hover:opacity-60"
                href="/my-offers"
              >
                My Offers
              </Link>
            )}

            <NavigationMenu>
              <NavigationMenuList>
                <NavigationMenuItem>
                  <NavigationMenuTrigger className={cn(
                    "h-auto p-0 font-[500] font-new-sans text-sm hover:bg-transparent hover:opacity-60 focus:bg-transparent",
                    isTransparent ? "text-white" : "text-foreground",
                  )}>
                    About
                  </NavigationMenuTrigger>
                  <NavigationMenuContent>
                    <ul className="flex w-[200px] flex-col gap-1 rounded-md border border-border bg-background p-2">
                      {ABOUT_LINKS.map((link) => (
                        <li key={link.href}>
                          <NavigationMenuLink asChild>
                            <Link
                              className="block rounded-sm px-3 py-2 font-normal text-sm transition-colors hover:bg-transparent hover:text-foreground"
                              href={link.href}
                            >
                              {link.title}
                            </Link>
                          </NavigationMenuLink>
                        </li>
                      ))}
                    </ul>
                  </NavigationMenuContent>
                </NavigationMenuItem>
              </NavigationMenuList>
            </NavigationMenu>
          </nav>

          <div className="flex justify-center">
            <Logo className="h-8 w-48" invert={isTransparent} />
          </div>

          <div className="flex items-center justify-end gap-3 xl:gap-5">
            <a
              className="flex items-center gap-2 hover:opacity-60"
              href={whatsappUrl}
              rel="noopener noreferrer"
              target="_blank"
            >
              <span className="hidden xl:inline">Text Us</span>
              <Image
                alt="WhatsApp"
                className={cn(isTransparent && "brightness-0 invert")}
                height={20}
                src="/new-design-images/icons/whatsup.svg"
                width={20}
              />
            </a>

            <Link
              className="whitespace-nowrap rounded bg-[#000E65] px-4 py-2 font-medium text-[12px] text-white transition-colors hover:bg-blue-900"
              href={APP_ROUTES.BUYBACK_REQUESTS.CREATE}
            >
              Start with a Quote
            </Link>

            {isAuthenticated ? (
              <div className="flex items-center gap-4">
                <HeaderNotificationsDropdown
                  bellClassName={isTransparent ? "text-secondary" : "text-foreground"}
                />
                <div
                  className={cn(
                    "h-8 w-[1px]",
                    isTransparent ? "bg-white/30" : "bg-[#D6D3D1]",
                  )}
                />
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <button
                      aria-label="User menu"
                      className="cursor-pointer overflow-hidden rounded-[4px] border border-transparent transition-colors hover:border-border focus:outline-none"
                      type="button"
                    >
                      <UserAvatar
                        firstName={profile?.firstName}
                        size={36}
                        src={avatarSrc}
                      />
                    </button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent
                    align="end"
                    className="w-[220px] rounded-xl border border-[#D6D3D1] bg-[#F5F3EF] p-1 shadow-[0px_4px_16px_rgba(0,0,0,0.08)]"
                    sideOffset={8}
                  >
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.PROFILE}
                      >
                        <CircleUserRound
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Profile Settings
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.WALLET.ROOT}
                      >
                        <WalletCards
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Accounts & Wallets
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.WALLET.PAYMENT_HISTORY}
                      >
                        <ScrollTextIcon
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Transaction History
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuSeparator className="my-1 bg-[#D6D3D1]" />
                    <DropdownMenuItem
                      className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                      onClick={handleLogout}
                    >
                      <LogOutIcon
                        className="shrink-0 text-[#44403C]"
                        size={16}
                      />
                      Logout
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Link
                  className="hover:opacity-60"
                  href={APP_ROUTES.AUTH.SIGN_IN}
                >
                  Login
                </Link>
                <div className="h-4 w-[1px] bg-black/10" />
                <Link
                  className="hover:opacity-60"
                  href={APP_ROUTES.AUTH.REGISTER}
                >
                  Register
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* --- Mobile Version --- */}
        <div className="flex items-center justify-between lg:hidden">
          <MobileMenu isAuthenticated={isAuthenticated} />

          <Logo className="h-6 w-32" invert={isTransparent} />

          <div className="flex items-center gap-3">
            <a
              aria-label="Contact on WhatsApp"
              className="hover:opacity-60"
              href={whatsappUrl}
              rel="noopener noreferrer"
              target="_blank"
            >
              <Image
                alt=""
                className={cn(isTransparent && "brightness-0 invert")}
                height={22}
                src="/new-design-images/icons/whatsup.svg"
                width={22}
              />
            </a>
            {isAuthenticated ? (
              <HeaderNotificationsDropdown />
            ) : (
              <Link className="text-md" href={APP_ROUTES.AUTH.SIGN_IN}>
                Login
              </Link>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

const Logo = ({
  className,
  invert,
}: {
  className: string;
  invert?: boolean;
}) => (
  <Link className={cn("relative", className)} href="/">
    <Image
      alt="LUXFLOW"
      className={cn(
        "object-contain transition-[filter] duration-300",
        invert && "brightness-0 invert",
      )}
      fill
      priority
      src="/new-design-images/header-logo.svg"
    />
  </Link>
);

"use client";

import {
  ArrowRight,
  BellIcon,
  ChevronDown,
  History,
  LogOutIcon,
  MenuIcon,
  User,
  WalletCards,
  X,
} from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { useState, type FC } from "react";

import { APP_ROUTES } from "@/shared/config/app-routes";
import { cn } from "@/shared/lib/ui/cn";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/shared/ui/shadcn/accordion";
import { NotificationBadge } from "@/shared/ui/shadcn/badge";
import { Button } from "@/shared/ui/shadcn/button";
import {
  Sheet,
  SheetClose,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/shared/ui/shadcn/sheet";

interface MobileMenuProps {
  isAuthenticated: boolean;
}

const SETTINGS_LINKS = [
  { title: "Profile Settings", href: "/settings/profile", icon: User },
  { title: "Accounts & Wallets", href: "/settings/accounts", icon: WalletCards },
  { title: "Transaction History", href: "/settings/history", icon: History },
];

const ABOUT_LINKS = [
  { title: "About LuxFlow", href: APP_ROUTES.APP.ABOUT },
  { title: "Our Method", href: APP_ROUTES.SERVICES.OUR_METHOD },
  { title: "Contact Us", href: APP_ROUTES.APP.CONTACT },
  { title: "Support", href: APP_ROUTES.APP.TERMS },
  { title: "FAQs", href: APP_ROUTES.APP.FAQ },
];

export const MobileMenu: FC<MobileMenuProps> = ({ isAuthenticated }) => {
  const [open, setOpen] = useState(false);

  const handleLinkClick = () => setOpen(false);

  const navLinkClass = "py-3 flex items-center justify-between";
  const settingLinkClass =
    "flex items-center gap-3 py-4 font-new-sans transition-opacity hover:opacity-70";
  const separatorClass = "my-4 h-[1.5px] w-full bg-[#D6D3D1]";

  return (
    <Sheet open={open} onOpenChange={setOpen}>
      <SheetTrigger asChild>
        <Button
          variant="simple"
          size="icon"
          className="h-6 w-6 min-[1172px]:hidden"
          aria-label="Open menu"
        >
          <MenuIcon size={24} />
        </Button>
      </SheetTrigger>

      <SheetContent
        side="left"
        className="new-design w-full border-none p-0 focus:ring-0"
      >
        <div className="flex h-full flex-col overflow-y-auto bg-[#F5F3EF] pb-12">
          <SheetHeader>
            <SheetTitle className="flex items-center justify-between border-[#D6D3D1] border-b-[1.5px] px-4 py-3">
              <SheetClose asChild>
                <Button variant="simple" size="icon" className="h-6 w-6 p-0">
                  <X className="h-6 w-6 font-normal text-primary" />
                </Button>
              </SheetClose>

              <Link
                href="/"
                onClick={handleLinkClick}
                className="relative h-6 w-32"
              >
                <Image
                  src="/new-design-images/header-logo.svg"
                  alt="LUXFLOW"
                  fill
                  className="object-contain"
                />
              </Link>

              <div className="flex items-center gap-2">
                <a
                  href="https://wa.me/971542739213"
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  <Image
                    src="/new-design-images/icons/whatsup.svg"
                    alt="WhatsApp"
                    width={20}
                    height={20}
                  />
                </a>
                {isAuthenticated ? (
                  <NotificationBadge className="cursor-pointer">
                    <BellIcon size={22} />
                  </NotificationBadge>
                ) : (
                  <Link
                    href={APP_ROUTES.AUTH.SIGN_IN}
                    onClick={handleLinkClick}
                    className="font-medium text-sm"
                  >
                    Login
                  </Link>
                )}
              </div>
            </SheetTitle>
          </SheetHeader>

          <div className="px-4 py-6">
            {isAuthenticated ? (
              <Button
                asChild
                className="flex w-full items-center justify-center gap-2 bg-[#0A1172] py-6 font-new-sans font-normal text-white hover:bg-[#0A1172]/90"
              >
                <Link
                  href={APP_ROUTES.SERVICES.DIRECT_SALE}
                  onClick={handleLinkClick}
                >
                  Start with a Quote <ArrowRight size={18} />
                </Link>
              </Button>
            ) : (
              <div className="grid grid-cols-2 gap-3">
                <Button
                  asChild
                  variant="default"
                  className="font-[400] font-new-sans"
                >
                  <Link
                    href={APP_ROUTES.AUTH.REGISTER}
                    onClick={handleLinkClick}
                  >
                    Register
                  </Link>
                </Button>
                <Button
                  asChild
                  variant="outline"
                  className="font-[400] font-new-sans"
                >
                  <Link
                    href={APP_ROUTES.AUTH.SIGN_IN}
                    onClick={handleLinkClick}
                  >
                    Login
                  </Link>
                </Button>
              </div>
            )}
          </div>

          <nav className="flex flex-col gap-2 px-4 font-light font-new-serif text-2xl">
            <Link href="/" onClick={handleLinkClick} className={navLinkClass}>
              Home
            </Link>

            {isAuthenticated && (
              <Link
                href="/my-offers"
                onClick={handleLinkClick}
                className={navLinkClass}
              >
                My Offers
              </Link>
            )}

            <Link
              href="/services/buyback"
              onClick={handleLinkClick}
              className={navLinkClass}
            >
              Buyback
            </Link>
            <Link
              href={APP_ROUTES.SERVICES.DIRECT_SALE}
              onClick={handleLinkClick}
              className={navLinkClass}
            >
              Final Sale
            </Link>

            <Accordion type="single" collapsible className="w-full">
              <AccordionItem value="about" className="border-none">
                <AccordionTrigger
                  className={cn(
                    navLinkClass,
                    "py-3 text-2xl hover:no-underline [&[data-state=open]>svg]:rotate-180",
                  )}
                >
                  About
                </AccordionTrigger>
                <AccordionContent className="mt-4 flex flex-col gap-1 font-new-sans text-sm">
                  {ABOUT_LINKS.map((link) => (
                    <Link
                      key={link.href}
                      href={link.href}
                      onClick={handleLinkClick}
                      className="py-2 transition-colors hover:text-primary"
                    >
                      {link.title}
                    </Link>
                  ))}
                </AccordionContent>
              </AccordionItem>
            </Accordion>

            <div className={separatorClass} />

            <div className="flex flex-col gap-6">
              <a
                href="https://wa.me/971542739213"
                target="_blank"
                rel="noopener noreferrer"
                className="flex w-fit items-center gap-2 font-light font-new-serif text-2xl text-[#1C1C1C]"
              >
                Text Us{" "}
                <Image
                  src="/new-design-images/icons/whatsup.svg"
                  alt=""
                  width={20}
                  height={20}
                  className="ml-1"
                />
              </a>

              {isAuthenticated && (
                <>
                  <div className="my-2 h-[1.5px] w-full bg-[#D6D3D1]" />
                  <div className="font-light font-new-serif text-2xl">
                    Settings
                  </div>
                  <div className="flex flex-col px-4 text-sm">
                    {SETTINGS_LINKS.map((item) => (
                      <Link
                        key={item.href}
                        href={item.href}
                        onClick={handleLinkClick}
                        className={settingLinkClass}
                      >
                        <item.icon size={20} /> {item.title}
                      </Link>
                    ))}
                  </div>
                  <div className="my-2 h-[1.5px] w-full bg-[#D6D3D1]" />
                  <Link
                    href="/logout"
                    onClick={handleLinkClick}
                    className="flex items-center gap-2 px-4 pl-5 font-new-sans font-normal text-sm transition-opacity hover:opacity-70"
                  >
                    <LogOutIcon size={20} />
                    <span>Logout</span>
                  </Link>
                </>
              )}

              <div className={separatorClass} />

